#include <stdio.h>
#include <stdlib.h>
#include <math.h>

int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

int is_closed(int* arr, int n) {
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            int g = gcd(arr[i], arr[j]);
            int found = 0;
            for (int k = 0; k < n; k++) {
                if (arr[k] == g) {
                    found = 1;
                    break;
                }
            }
            if (!found) return 0;
        }
    }
    return 1;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K, L;
        scanf("%d %d %d", &N, &K, &L);
        int* arr = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &arr[i]);
        }
        int count = 0;
        for (int mask = 0; mask < (1 << L); mask++) {
            int* new_arr = (int*)malloc((N + K) * sizeof(int));
            int new_n = 0;
            for (int i = 0; i < N; i++) {
                new_arr[new_n++] = arr[i];
            }
            for (int i = 0; i < L; i++) {
                if ((mask & (1 << i)) != 0) {
                    new_arr[new_n++] = i + 1;
                }
            }
            if (new_n == N + K && is_closed(new_arr, new_n)) {
                count++;
            }
            free(new_arr);
        }
        printf("%d\n", count);
        free(arr);
    }
    return 0;
}

