using namespace std;

int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

bool is_closed(vector<int>& arr) {
    for (int i = 0; i < arr.size(); i++) {
        for (int j = i + 1; j < arr.size(); j++) {
            int g = gcd(arr[i], arr[j]);
            bool found = false;
            for (int k = 0; k < arr.size(); k++) {
                if (arr[k] == g) {
                    found = true;
                    break;
                }
            }
            if (!found) return false;
        }
    }
    return true;
}

int main() {
    int T;
    cin >> T;
    while (T--) {
        int N, K, L;
        cin >> N >> K >> L;
        vector<int> arr(N);
        for (int i = 0; i < N; i++) {
            cin >> arr[i];
        }
        int count = 0;
        for (int mask = 0; mask < (1 << L); mask++) {
            vector<int> new_arr = arr;
            for (int i = 0; i < L; i++) {
                if ((mask & (1 << i)) != 0) {
                    new_arr.push_back(i + 1);
                }
            }
            if (new_arr.size() == N + K && is_closed(new_arr)) {
                count++;
            }
        }
        cout << count << endl;
    }
    return 0;
}

