import java.util.Scanner;
public class Main {
    public static int gcd(int a, int b) {
        if (b == 0) return a;
        return gcd(b, a % b);
    }

    public static boolean is_closed(int[] arr) {
        for (int i = 0; i < arr.length; i++) {
            for (int j = i + 1; j < arr.length; j++) {
                int g = gcd(arr[i], arr[j]);
                boolean found = false;
                for (int k = 0; k < arr.length; k++) {
                    if (arr[k] == g) {
                        found = true;
                        break;
                    }
                }
                if (!found) return false;
            }
        }
        return true;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            int L = sc.nextInt();
            int[] arr = new int[N];
            for (int i = 0; i < N; i++) {
                arr[i] = sc.nextInt();
            }
            int count = 0;
            for (int mask = 0; mask < (1 << L); mask++) {
                int[] new_arr = new int[N + K];
                int new_n = 0;
                for (int i = 0; i < N; i++) {
                    new_arr[new_n++] = arr[i];
                }
                for (int i = 0; i < L; i++) {
                    if ((mask & (1 << i)) != 0) {
                        new_arr[new_n++] = i + 1;
                    }
                }
                if (new_n == N + K && is_closed(new_arr)) {
                    count++;
                }
            }
            System.out.println(count);
        }
    }
}

